module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

reg [15:0] a_reg;
reg [7:0] b_reg;

always @* begin
    a_reg = A;
    b_reg = B;

    if (b_reg != 0) begin
        result = a_reg / b_reg;
        odd = a_reg % b_reg;
    end else begin
        result = 0;
        odd = a_reg;
    end
end
endmodule

module width_8to16 (
    input 				   clk,
    input 				   rst_n,
    input				      valid_in,
    input	   [7:0]		   data_in,
    output	reg			valid_out,
    output   reg [15:0]	data_out
);

reg [7:0] data_lock;
reg flag;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data_out <= 16'b0;
        valid_out <= 1'b0;
        data_lock <= 8'b0;
        flag <= 1'b0;
    end else begin
        if (valid_in && flag) begin
            data_out <= {data_lock, data_in};
            valid_out <= 1'b1;
            flag <= 1'b0;
        end else if (valid_in && !flag) begin
            data_lock <= data_in;
            flag <= 1'b1;
            valid_out <= 1'b0;
        end else begin
            valid_out <= 1'b0;
        end
    end
end
endmodule

module multi_8bit (
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] product_reg;
    reg [7:0] multiplicand;
    reg [7:0] multiplier;
    integer i;

    always @(*) begin
        multiplicand = A;
        multiplier = B;
        product_reg = 16'd0;

        for (i = 0; i < 8; i = i + 1) begin
            if (multiplier[i]) begin
                product_reg = product_reg + (multiplicand << i);
            end
        end

        product = product_reg;
    end

endmodule

module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output reg valid_out,
    output reg dout
);

    reg [1:0] cnt;
    reg [3:0] data;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 2'b00;
            data <= 4'b0000;
            valid_out <= 1'b0;
        end else begin
            if (cnt == 2'b11) begin
                cnt <= 2'b00;
                data <= d;
                valid_out <= 1'b1;
            end else begin
                cnt <= cnt + 1;
                data <= {data[2:0], data[3]};
                valid_out <= 1'b0;
            end
        end
    end

    assign dout = data[3];

endmodule

module serial2parallel (
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0]dout_parallel,
    output reg dout_valid
);

reg [3:0] cnt;
reg [7:0] shift_reg;

always @(posedge clk) begin
    if (!rst_n) begin
        cnt <= 4'b0000;
        shift_reg <= 8'b0;
        dout_parallel <= 8'b0;
        dout_valid <= 1'b0;
    end else begin
        if (din_valid) begin
            shift_reg <= {shift_reg[6:0], din_serial};
            cnt <= cnt + 4'b0001;
            if (cnt == 4'b1000) begin
                dout_parallel <= shift_reg;
                dout_valid <= 1'b1;
            end else begin
                dout_valid <= 1'b0;
            end
        end else begin
            dout_valid <= 1'b0;
        end
    end
end

endmodule

module edge_detect (
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin

        rise <= 1'b0;
        down <= 1'b0;
    end else begin

        if (a && !prev_a) begin

            rise <= 1'b1;
            down <= 1'b0;
        end else if (!a && prev_a) begin

            rise <= 1'b0;
            down <= 1'b1;
        end else begin

            rise <= 1'b0;
            down <= 1'b0;
        end
    end
end

reg prev_a;

always @(posedge clk) begin

    prev_a <= a;
end
endmodule

