module cla_4bit(
    input [3:0] a,
    input [3:0] b,
    input cin,
    output [3:0] sum,
    output cout,
    output p_group,
    output g_group
);
    wire [3:0] p; 
    wire [3:0] g; 
    wire [4:0] c; 


    assign p = a ^ b;
    assign g = a & b;


    assign c[0] = cin;
    assign c[1] = g[0] | (p[0] & c[0]);
    assign c[2] = g[1] | (p[1] & c[1]);
    assign c[3] = g[2] | (p[2] & c[2]);
    assign c[4] = g[3] | (p[3] & c[3]);


    assign sum = p ^ {c[3:0]};


    assign p_group = p[0] & p[1] & p[2] & p[3];
    assign g_group = g[3] | (g[2] & p[3]) | (g[1] & p[3] & p[2]) | (g[0] & p[3] & p[2] & p[1]);


    assign cout = c[4];
endmodule

module signal_generator (
    input clk,
    input rst_n,
    output reg [4:0] wave
);

localparam UP_STATE = 2'b00;
localparam DOWN_STATE = 2'b01;

reg [1:0] state;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        state <= UP_STATE;
        wave <= 5'b0;
    end else begin
        case (state)
            UP_STATE: begin
                if (wave == 5'b11111) begin
                    state <= DOWN_STATE;
                end else begin
                    wave <= wave + 1;
                end
            end
            DOWN_STATE: begin
                if (wave == 5'b00000) begin
                    state <= UP_STATE;
                end else begin
                    wave <= wave - 1;
                end
            end
        endcase
    end
end

endmodule

module multi_16bit (
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);
    reg [4:0] i;
    reg done_r;
    reg [15:0] areg, breg;
    reg [31:0] yout_r;
    assign done = done_r;
    assign yout = yout_r;
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            i <= 5'd0;
        end
        else if(start && i < 5'd17) begin
            i <= i + 1;
        end
        else if(!start) begin
            i <= 5'd0;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            done_r <= 1'b0;
        end
        else if(i == 5'd16) begin
            done_r <= 1'b1;
        end
        else if(i == 5'd17) begin
            done_r <= 1'b0;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            areg <= 16'd0;
            breg <= 16'd0;
            yout_r <= 32'd0;
        end
        else if(start) begin
            if(i == 5'd0) begin
                areg <= ain;
                breg <= bin;
            end
            else if(i > 5'd0 && i < 5'd17) begin
                if(areg[i-1]) begin
                    yout_r <= yout_r + (breg << (i-1));
                end
            end
        end
    end
endmodule

