module accu (
    input               clk,
    input               rst_n,
    input       [7:0]   data_in,
    input               valid_in,
    output  reg         valid_out,
    output  reg [9:0]   data_out
);

reg [3:0] counter;
reg [9:0] temp_sum;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin

        data_out <= 10'd0;
        valid_out <= 1'b0;
        counter <= 4'd0;
        temp_sum <= 10'd0;
    end else begin

        if (valid_in == 1'b1) begin

            temp_sum <= temp_sum + {2'b00, data_in};

            counter <= counter + 1;

            if (counter == 4'd4) begin

                data_out <= temp_sum;

                valid_out <= 1'b1;

                counter <= 4'd0;
                temp_sum <= 10'd0;
            end else begin

                valid_out <= 1'b0;
            end
        end else begin

            valid_out <= 1'b0;
        end
    end
end
endmodule

