module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

    wire [size-1:0] mul_a_ext;
    wire [size-1:0] mul_b_ext;
    assign mul_a_ext = {size{1'b0}} | mul_a;
    assign mul_b_ext = {size{1'b0}} | mul_b;
    reg [7:0] sum_tmp1;
    reg [7:0] sum_tmp2;
    reg [7:0] mul_out_reg;
    assign mul_out = mul_out_reg;
    always@(posedge clk or negedge rst_n) begin
        if(~rst_n) begin
            sum_tmp1 <= 8'b0;
            sum_tmp2 <= 8'b0;
            mul_out_reg <= 8'b0;
        end
        else begin
            sum_tmp1 <= ((mul_b_ext[0] ? mul_a_ext : 8'b0) + (mul_b_ext[1] ? mul_a_ext << 1 : 8'b0));
            sum_tmp2 <= ((mul_b_ext[2] ? mul_a_ext << 2 : 8'b0) + (mul_b_ext[3] ? mul_a_ext << 3 : 8'b0));
            mul_out_reg <= sum_tmp1 + sum_tmp2;
        end
    end

endmodule

module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output reg [15:0] result
);

    reg [16:0] sr;
    reg [7:0] divisor_reg;
    reg [7:0] neg_divisor;
    reg [3:0] cnt;
    reg [3:0] start_cnt;
    reg [7:0] remainder;
    reg [7:0] quotient;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            sr <= 0;
            divisor_reg <= 0;
            neg_divisor <= 0;
            cnt <= 0;
            start_cnt <= 0;
            remainder <= 0;
            quotient <= 0;
            res_valid <= 0;
            result <= 0;
        end else begin
            if (opn_valid && !res_valid) begin
                if (divisor == 0) begin

                end else begin
                    divisor_reg <= divisor;
                    neg_divisor <= -divisor;
                    remainder <= 0;
                    quotient <= 0;
                    start_cnt <= 8;
                end
            end

            if (start_cnt > 0) begin
                start_cnt <= start_cnt - 1;
            end else begin
                if (sign && (dividend[7] ^ divisor[7])) begin
                    remainder <= dividend[15:8] - divisor_reg;
                    quotient <= dividend[7:0];
                end else begin
                    remainder <= dividend[15:8] + divisor_reg;
                    quotient <= dividend[7:0];
                end

                if (remainder[7] == 0) begin
                    sr <= {remainder[6:0], dividend[7:0]};
                    cnt <= 8;
                end else begin
                    sr <= {remainder[6:0], dividend[7:0]};
                    cnt <= 8;
                end
            end

            if (cnt == 8) begin
                if (res_ready) begin
                    result <= {remainder, quotient};
                    res_valid <= 1;
                end
            end else if (res_valid && res_ready) begin
                res_valid <= 0;
            end
        end
    end

endmodule

module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

parameter IDLE = 3'b000;
parameter PULSE_START = 3'b001;
parameter PULSE_END = 3'b010;

reg [2:0] state;

reg [2:0] next_state;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        state <= IDLE;
    end else begin
        state <= next_state;
    end
end

always @(*) begin
    case(state)
        IDLE: begin
            if (data_in == 1'b1 && ~data_in) begin
                next_state = PULSE_START;
            end else begin
                next_state = IDLE;
            end
        end
        PULSE_START: begin
            if (~data_in) begin
                next_state = PULSE_END;
            end else begin
                next_state = PULSE_START;
            end
        end
        PULSE_END: begin
            if (data_in) begin
                next_state = IDLE;
            end else begin
                next_state = PULSE_END;
            end
        end
        default: next_state = IDLE;
    endcase
end

always @(*) begin
    if ((state == PULSE_END) && (data_in == 1'b0)) begin
        data_out = 1'b1;
    end else begin
        data_out = 1'b0;
    end
end
endmodule

