) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

    parameter WIDTH_A = 8;
    parameter WIDTH_B = 8;
    parameter WIDTH_OUT = 16;

    reg [1:0] mul_en_out_reg;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            mul_en_out_reg <= 0;
            mul_en_out <= 0;
        end else begin
            mul_en_out_reg <= {mul_en_out_reg[0], mul_en_in};
            mul_en_out <= mul_en_out_reg[1];
        end
    end

    reg [WIDTH_A-1:0] mul_a_reg;
    reg [WIDTH_B-1:0] mul_b_reg;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            mul_a_reg <= 0;
            mul_b_reg <= 0;
        end else begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
        end
    end

    wire [WIDTH_A+WIDTH_B-1:0] temp[0:7];

    assign temp[0] = {9'd0, mul_a_reg[0] ? mul_b_reg : 8'd0};
    assign temp[1] = {8'd0, mul_a_reg[1] ? mul_b_reg : 8'd0, 1'd0};
    assign temp[2] = {7'd0, mul_a_reg[2] ? mul_b_reg : 8'd0, 2'd0};
    assign temp[3] = {6'd0, mul_a_reg[3] ? mul_b_reg : 8'd0, 3'd0};
    assign temp[4] = {5'd0, mul_a_reg[4] ? mul_b_reg : 8'd0, 4'd0};
    assign temp[5] = {4'd0, mul_a_reg[5] ? mul_b_reg : 8'd0, 5'd0};
    assign temp[6] = {3'd0, mul_a_reg[6] ? mul_b_reg : 8'd0, 6'd0};
    assign temp[7] = {2'd0, mul_a_reg[7] ? mul_b_reg : 8'd0, 7'd0};

    reg [WIDTH_A+WIDTH_B-1:0] sum[0:6];

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            sum[0] <= 0;
            sum[1] <= 0;
            sum[2] <= 0;
            sum[3] <= 0;
            sum[4] <= 0;
            sum[5] <= 0;
            sum[6] <= 0;
        end else begin
            sum[0] <= temp[0];
            sum[1] <= temp[1] + temp[2];
            sum[2] <= temp[3] + temp[4];
            sum[3] <= temp[5] + temp[6];
            sum[4] <= temp[7];
        end
    end

    reg [WIDTH_OUT-1:0] mul_out_reg;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            mul_out_reg <= 0;
        end else begin
            mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3] + sum[4];
        end
    end

    assign mul_out = mul_en_out_reg[1] ? mul_out_reg : 0;
endmodule

module traffic_light #(
    parameter idle = 2'd0,
    parameter s1_red = 2'd1,
    parameter s2_yellow = 2'd2,
    parameter s3_green = 2'd3
) (
    input rst_n,
    input clk,
    input pass_request,
    output wire[7:0]clock,
    output reg red,
    output reg yellow,
    output reg green
);
reg [7:0] cnt;
reg [1:0] state;
reg p_red, p_yellow, p_green;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= idle;
        cnt <= 8'd0;
        red <= 1'b0;
        yellow <= 1'b0;
        green <= 1'b0;
    end else begin
        case (state)
            idle: begin
                cnt <= 8'd0;
                red <= 1'b0;
                yellow <= 1'b0;
                green <= 1'b0;
                state <= s1_red;
            end
            s1_red: begin
                red <= 1'b1;
                yellow <= 1'b0;
                green <= 1'b0;
                if (cnt == 8'd3) begin
                    state <= s2_yellow;
                    cnt <= 8'd0;
                end else begin
                    cnt <= cnt + 8'd1;
                end
            end
            s2_yellow: begin
                red <= 1'b0;
                yellow <= 1'b1;
                green <= 1'b0;
                if (cnt == 8'd3) begin
                    state <= s3_green;
                    cnt <= 8'd0;
                end else begin
                    cnt <= cnt + 8'd1;
                end
            end
            s3_green: begin
                red <= 1'b0;
                yellow <= 1'b0;
                green <= 1'b1;
                if (cnt == 8'd3) begin
                    state <= s2_yellow;
                    cnt <= 8'd0;
                end else begin
                    cnt <= cnt + 8'd1;
                end
            end
            default: begin
                state <= idle;
            end
        endcase
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        p_red <= 1'b0;
        p_yellow <= 1'b0;
        p_green <= 1'b0;
    end else begin
        p_red <= red;
        p_yellow <= yellow;
        p_green <= green;
    end
end
assign clock = cnt;
endmodule

module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output reg wfull,
    output reg rempty,
    output reg [WIDTH-1:0]	rdata
);

reg [WIDTH-1:0] ram [DEPTH-1:0];
reg [ADDR_WIDTH-1:0] wptr, rptr;
wire [ADDR_WIDTH-1:0] waddr, raddr;

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wptr <= 0;
    end else if (winc) begin
        wptr <= wptr + 1'b1;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rptr <= 0;
    end else if (rinc) begin
        rptr <= rptr + 1'b1;
    end
end

reg [ADDR_WIDTH-1:0] rptr_rsync1, rptr_rsync2;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        rptr_rsync1 <= 0;
        rptr_rsync2 <= 0;
    end else begin
        rptr_rsync1 <= rptr;
        rptr_rsync2 <= rptr_rsync1;
    end
end

reg [ADDR_WIDTH-1:0] wptr_wsync1, wptr_wsync2;
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        wptr_wsync1 <= 0;
        wptr_wsync2 <= 0;
    end else begin
        wptr_wsync1 <= wptr;
        wptr_wsync2 <= wptr_wsync1;
    end
end

assign raddr = rptr_rsync2;
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rdata <= 0;
    end else begin
        rdata <= ram[raddr];
    end
end

assign waddr = wptr_wsync2;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        ram[waddr] <= 0;
    end else if (winc) begin
        ram[waddr] <= wdata;
    end
end

always @(*) begin
    if (wptr_wsync2 == rptr_rsync2) begin
        if (winc && !rinc) begin
            wfull <= 1'b1;
            rempty <= 1'b0;
        end else begin
            wfull <= 1'b0;
            rempty <= 1'b1;
        end
    end else if (wptr_wsync2 > rptr_rsync2) begin
        if (wptr_wsync2 - rptr_rsync2 == 1) begin
            wfull <= 1'b1;
            rempty <= 1'b0;
        end else begin
            wfull <= 1'b0;
            rempty <= 1'b0;
        end
    end else begin
        if (rptr_rsync2 - wptr_wsync2 == 1) begin
            wfull <= 1'b0;
            rempty <= 1'b1;
        end else begin
            wfull <= 1'b0;
            rempty <= 1'b0;
        end
    end
end

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule

module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output reg carry,
    output negative,
    output reg overflow,
    output flag
);
reg [31:0] res;
assign r = res[31:0];
assign zero = &res;
assign negative = res[31];
assign flag = (aluc == SLT || aluc == SLTU) ? res[0] : 1'bz;
always @(*) begin
    case (aluc)
        ADD: begin
            {carry, res} = {a[31], a} + {b[31], b};
            overflow = (a[31] == b[31]) && (res[31] != a[31]);
        end
        ADDU: begin
            {carry, res} = {1'b0, a} + {1'b0, b};
            overflow = 1'b0;
        end
        SUB: begin
            {carry, res} = {a[31], a} - {b[31], b};
            overflow = (a[31] != b[31]) && (res[31] != a[31]);
        end
        SUBU: begin
            {carry, res} = {1'b0, a} - {1'b0, b};
            overflow = 1'b0;
        end
        AND: begin
            res = a & b;
            carry = 1'b0;
            overflow = 1'b0;
        end
        OR: begin
            res = a | b;
            carry = 1'b0;
            overflow = 1'b0;
        end
        XOR: begin
            res = a ^ b;
            carry = 1'b0;
            overflow = 1'b0;
        end
        NOR: begin
            res = ~(a | b);
            carry = 1'b0;
            overflow = 1'b0;
        end
        SLT: begin
            res = (a < b) ? 32'b1 : 32'b0;
            carry = 1'b0;
            overflow = 1'b0;
        end
        SLTU: begin
            res = (a < b) ? 32'b1 : 32'b0;
            carry = 1'b0;
            overflow = 1'b0;
        end
        SLL: begin
            res = b << a[4:0];
            carry = 1'b0;
            overflow = 1'b0;
        end
        SRL: begin
            res = b >> a[4:0];
            carry = 1'b0;
            overflow = 1'b0;
        end
        SRA: begin
            res = b >>> a[4:0];
            carry = 1'b0;
            overflow = 1'b0;
        end
        SLLV: begin
            res = b << a[4:0];
            carry = 1'b0;
            overflow = 1'b0;
        end
        SRLV: begin
            res = b >> a[4:0];
            carry = 1'b0;
            overflow = 1'b0;
        end
        SRAV: begin
            res = b >>> a[4:0];
            carry = 1'b0;
            overflow = 1'b0;
        end
        LUI: begin
            res = {b[15:0], 16'b0};
            carry = 1'b0;
            overflow = 1'b0;
        end
        default: begin
            res = 32'b0;
            carry = 1'b0;
            overflow = 1'b0;
        end
    endcase
end
endmodule
